use actix_web::{web, App, HttpResponse, HttpServer};
use std::fs;
use std::io;

fn serve_file(filename: String) -> Result<HttpResponse, io::Error> {
    let uploads_dir = "uploads";
    let file_path = format!("{}/{}", uploads_dir, filename);

    if !filename.starts_with(uploads_dir) {
        return Err(io::Error::new(
            io::ErrorKind::InvalidInput,
            "Path traversal attempt",
        ));
    }

    let contents = fs::read_to_string(file_path)?;
    Ok(HttpResponse::Ok().body(contents))
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new()
            .service(
                web::resource("/files/{filename}")
                    .route(web::get().to(serve_file)),
            )
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}